// String type holds text — use double or single quotes
let productName: string = 'Organic Coffee';
// Number type holds integers and decimals alike
let price: number = 15.99;
// Boolean type holds true or false only
let inStock: boolean = true;
// Const variables cannot be reassigned after creation
const storeName: string = 'Corner Market';
// Null represents an intentionally empty value
let discount: null = null;
// Undefined means a variable has not been assigned yet
let couponCode: undefined = undefined;
// Print all values to see them together
console.log(productName, price, inStock, storeName);
// Expected: Organic Coffee 15.99 true Corner Market
